import React, { useEffect } from 'react';
import Navigation from './components/Navigation';
import Hero from './components/Hero';

function App() {
  useEffect(() => {
    // #region agent log
    fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:useEffect',message:'App component mounted',data:{rootExists:!!document.getElementById('root'),bodyBg:getComputedStyle(document.body).backgroundColor},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{});
    // #endregion
  }, []);

  return (
    <div className="App">
      {/* #region agent log */}
      {(() => { fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:render',message:'App rendering',data:{hasNav:true,hasHero:true},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{}); return null; })()}
      {/* #endregion */}
      <Navigation />
      <Hero />
    </div>
  );
}

export default App;
